import json
import csv
import io
import re
import zipfile
import logging
from typing import Dict, Any, Tuple
from app.schemas.document import Document, DocumentMetadata

logger = logging.getLogger("app.services.document_loader")

class DocumentLoader:
    @staticmethod
    def load_text(content_bytes: bytes, filename: str) -> Tuple[str, Dict[str, Any]]:
        """Parses plain text / markdown files."""
        try:
            text = content_bytes.decode("utf-8")
        except UnicodeDecodeError:
            text = content_bytes.decode("latin-1", errors="ignore")

        metadata = {
            "title": filename.rsplit(".", 1)[0].replace("_", " ").title(),
            "source": filename,
            "category": "general"
        }
        return text, metadata

    @staticmethod
    def load_json(content_bytes: bytes, filename: str) -> Tuple[str, Dict[str, Any]]:
        """Parses structured JSON documents."""
        try:
            data = json.loads(content_bytes.decode("utf-8"))
            if isinstance(data, dict):
                text_parts = []
                for k, v in data.items():
                    text_parts.append(f"{k}: {v}")
                text = "\n".join(text_parts)
                metadata = {
                    "title": data.get("title", filename.rsplit(".", 1)[0].replace("_", " ").title()),
                    "category": data.get("category", "faq")
                }
            elif isinstance(data, list):
                text = json.dumps(data, indent=2)
                metadata = {"title": filename, "category": "kb_list"}
            else:
                text = str(data)
                metadata = {"title": filename}
        except Exception as e:
            logger.error(f"Failed to parse JSON file {filename}: {e}")
            text = content_bytes.decode("utf-8", errors="ignore")
            metadata = {"title": filename}

        metadata["source"] = filename
        return text, metadata

    @staticmethod
    def load_csv(content_bytes: bytes, filename: str) -> Tuple[str, Dict[str, Any]]:
        """Parses CSV files into table-like formatted text."""
        try:
            text_stream = io.StringIO(content_bytes.decode("utf-8"))
        except UnicodeDecodeError:
            text_stream = io.StringIO(content_bytes.decode("latin-1", errors="ignore"))

        reader = csv.reader(text_stream)
        rows = list(reader)

        if not rows:
            return "", {"source": filename}

        formatted_parts = []
        headers = rows[0]
        for idx, row in enumerate(rows[1:], start=1):
            row_str = ", ".join([f"{headers[i] if i < len(headers) else 'col_' + str(i)}: {val}" for i, val in enumerate(row)])
            formatted_parts.append(f"Record {idx}: {row_str}")

        text = "\n".join(formatted_parts)
        metadata = {
            "title": filename.rsplit(".", 1)[0].replace("_", " ").title(),
            "source": filename,
            "category": "database_export"
        }
        return text, metadata

    @staticmethod
    def load_html(content_bytes: bytes, filename: str) -> Tuple[str, Dict[str, Any]]:
        """Parses HTML files, stripping tags and scripts."""
        try:
            html_content = content_bytes.decode("utf-8")
        except UnicodeDecodeError:
            html_content = content_bytes.decode("latin-1", errors="ignore")

        # Strip script and style tags
        html_content = re.sub(r"<script.*?>.*?</script>", "", html_content, flags=re.DOTALL | re.IGNORECASE)
        html_content = re.sub(r"<style.*?>.*?</style>", "", html_content, flags=re.DOTALL | re.IGNORECASE)
        # Strip all other HTML tags
        text = re.sub(r"<[^>]+>", " ", html_content)
        # Clean extra whitespace
        text = re.sub(r"\s+", " ", text).strip()

        title_match = re.search(r"<title>(.*?)</title>", html_content, re.IGNORECASE)
        title = title_match.group(1).strip() if title_match else filename.rsplit(".", 1)[0]

        metadata = {
            "title": title,
            "source": filename,
            "category": "web_page"
        }
        return text, metadata

    @staticmethod
    def load_docx(content_bytes: bytes, filename: str) -> Tuple[str, Dict[str, Any]]:
        """Parses DOCX files by reading its internal document.xml (Office Open XML)."""
        text_parts = []
        try:
            with zipfile.ZipFile(io.BytesIO(content_bytes)) as docx_zip:
                doc_xml = docx_zip.read("word/document.xml")
                # Simple regex XML paragraph parsing to avoid dependencies
                # Matches <w:t>...</w:t> tags
                text_runs = re.findall(r"<w:t.*?>(.*?)</w:t>", doc_xml.decode("utf-8"))
                text_parts.append(" ".join(text_runs))
        except Exception as e:
            logger.error(f"Failed to parse DOCX file {filename}: {e}")
            text_parts.append(content_bytes.decode("utf-8", errors="ignore"))

        text = "\n".join(text_parts)
        # Clean up XML entities
        text = text.replace("&lt;", "<").replace("&gt;", ">").replace("&amp;", "&")

        metadata = {
            "title": filename.rsplit(".", 1)[0].replace("_", " ").title(),
            "source": filename,
            "category": "document"
        }
        return text, metadata

    @staticmethod
    def load_pdf(content_bytes: bytes, filename: str) -> Tuple[str, Dict[str, Any]]:
        """Parses PDF files. Fallback to basic string extraction of text stream tokens."""
        text_parts = []
        try:
            pdf_data = content_bytes.decode("latin-1", errors="ignore")
            # PDF text streams are inside objects: Tj, TJ, BT ... ET
            # Simple extractor looking for Tj/TJ commands
            matches = re.findall(r"\((.*?)\)\s*Tj", pdf_data)
            if matches:
                text_parts.append(" ".join(matches))
            else:
                # Fallback: extract clean printable words
                words = re.findall(r"[A-Za-z0-9\s\-\.\,\?\!\'\"]{4,}", pdf_data)
                cleaned_words = [w for w in words if "obj" not in w and "endobj" not in w and "stream" not in w]
                text_parts.append(" ".join(cleaned_words[:5000])) # cap to avoid binary dump
        except Exception as e:
            logger.error(f"Failed to parse PDF file {filename}: {e}")

        text = " ".join(text_parts)
        # Clean escape sequences common in PDF text
        text = re.sub(r"\\([0-7]{3})", "", text) # octave escapes
        text = text.replace("\\(", "(").replace("\\)", ")")

        metadata = {
            "title": filename.rsplit(".", 1)[0].replace("_", " ").title(),
            "source": filename,
            "category": "manual"
        }
        return text, metadata

    @classmethod
    def load_document(cls, file_content: bytes, filename: str) -> Document:
        """Determines the loader based on the file extension and returns a Document."""
        ext = filename.split(".")[-1].lower() if "." in filename else "txt"

        if ext in ["json"]:
            text, meta_dict = cls.load_json(file_content, filename)
            mime = "application/json"
        elif ext in ["csv"]:
            text, meta_dict = cls.load_csv(file_content, filename)
            mime = "text/csv"
        elif ext in ["html", "htm"]:
            text, meta_dict = cls.load_html(file_content, filename)
            mime = "text/html"
        elif ext in ["docx"]:
            text, meta_dict = cls.load_docx(file_content, filename)
            mime = "application/vnd.openxmlformats-officedocument.wordprocessingml.document"
        elif ext in ["pdf"]:
            text, meta_dict = cls.load_pdf(file_content, filename)
            mime = "application/pdf"
        else: # txt, md, markdown
            text, meta_dict = cls.load_text(file_content, filename)
            mime = "text/plain"

        # Construct safe ID
        doc_id = f"DOC-{hash(filename) % 100000:05d}"

        metadata = DocumentMetadata(
            title=meta_dict.get("title"),
            source=meta_dict.get("source"),
            category=meta_dict.get("category", "general"),
            product=meta_dict.get("product"),
            custom_metadata={k: v for k, v in meta_dict.items() if k not in ["title", "source", "category", "product"]}
        )

        return Document(
            id=doc_id,
            content=text,
            metadata=metadata,
            mime_type=mime,
            chunk_count=0
        )

import os
import urllib.request
import urllib.error
import json
import logging
import math
from typing import List

logger = logging.getLogger("app.services.embedding_service")

class EmbeddingService:
    def __init__(self, api_key: str = None, model_name: str = "text-embedding-004"):
        self.api_key = api_key or os.getenv("GEMINI_API_KEY")
        self.model_name = model_name
        self.base_url = "https://generativelanguage.googleapis.com/v1beta/models"

    def embed_text(self, text: str) -> List[float]:
        """
        Generates a vector embedding for the input text using Gemini's text-embedding-004.
        If it fails, or the API key is not configured, falls back to a deterministic, high-quality
        TF-IDF character frequency embedding so calculations remain locally operational.
        """
        if not text.strip():
            return [0.0] * 768

        if self.api_key:
            url = f"{self.base_url}/{self.model_name}:embedContent?key={self.api_key}"
            payload = {
                "model": f"models/{self.model_name}",
                "content": {
                    "parts": [{"text": text}]
                }
            }
            headers = {
                "Content-Type": "application/json"
            }
            try:
                req = urllib.request.Request(
                    url,
                    data=json.dumps(payload).encode("utf-8"),
                    headers=headers,
                    method="POST"
                )
                with urllib.request.urlopen(req, timeout=10) as response:
                    res_data = json.loads(response.read().decode("utf-8"))
                    embedding = res_data["embedding"]["values"]
                    return embedding
            except Exception as e:
                logger.warning(f"Failed to fetch Gemini Embedding: {e}. Falling back to local semantic encoder.")

        return self._generate_local_embedding(text)

    def embed_batch(self, texts: List[str]) -> List[List[float]]:
        """
        Generates embeddings for a batch of text.
        """
        # Batch endpoint
        if self.api_key and len(texts) > 0:
            url = f"{self.base_url}/{self.model_name}:batchEmbedContents?key={self.api_key}"
            requests_payload = [
                {
                    "model": f"models/{self.model_name}",
                    "content": {"parts": [{"text": text}]}
                }
                for text in texts
            ]
            payload = {"requests": requests_payload}
            headers = {"Content-Type": "application/json"}
            try:
                req = urllib.request.Request(
                    url,
                    data=json.dumps(payload).encode("utf-8"),
                    headers=headers,
                    method="POST"
                )
                with urllib.request.urlopen(req, timeout=20) as response:
                    res_data = json.loads(response.read().decode("utf-8"))
                    embeddings = [emb["values"] for emb in res_data["embeddings"]]
                    return embeddings
            except Exception as e:
                logger.warning(f"Batch embedding failed: {e}. Processing individually with fallback.")

        return [self.embed_text(t) for t in texts]

    def _generate_local_embedding(self, text: str, dimensions: int = 768) -> List[float]:
        """
        A high-quality, deterministic character-n-gram hash-based local encoder.
        This represents the text semantics in a normalized 768-dimensional space, allowing
        cosine similarity calculations to work seamlessly when offline or without API keys.
        """
        vector = [0.0] * dimensions
        text = text.lower()

        # Extract char 3-grams
        ngrams = [text[i:i+3] for i in range(len(text)-2)]
        if not ngrams:
            ngrams = [text]

        # Use FNV-1a like hashing to distribute ngrams across the dimensions
        for ngram in ngrams:
            h = 2166136261
            for char in ngram:
                h = h ^ ord(char)
                h = (h * 16777619) & 0xffffffff

            # Map hash to index and sign (+1 or -1 for random projection)
            idx = h % dimensions
            sign = 1.0 if ((h >> 5) & 1) == 1 else -1.0
            vector[idx] += sign

        # L2 Normalize the vector
        magnitude = math.sqrt(sum(v * v for v in vector))
        if magnitude > 0:
            vector = [v / magnitude for v in vector]

        return vector

    @staticmethod
    def cosine_similarity(v1: List[float], v2: List[float]) -> float:
        """Computes cosine similarity between two vectors."""
        if not v1 or not v2 or len(v1) != len(v2):
            return 0.0

        dot_product = sum(a * b for a, b in zip(v1, v2))
        mag1 = math.sqrt(sum(a * a for a in v1))
        mag2 = math.sqrt(sum(b * b for b in v2))

        if mag1 == 0.0 or mag2 == 0.0:
            return 0.0

        return dot_product / (mag1 * mag2)

def get_embedding_service() -> EmbeddingService:
    return EmbeddingService()

import logging
import abc
from typing import List, Dict, Any, Optional
from app.schemas.chunk import Chunk
from app.services.embedding_service import get_embedding_service, EmbeddingService

logger = logging.getLogger("app.services.vector_store")

class VectorStore(abc.ABC):
    @abc.abstractmethod
    def add_chunks(self, chunks: List[Chunk]) -> None:
        """Adds a list of chunks with their pre-computed embeddings to the vector store."""
        pass

    @abc.abstractmethod
    def similarity_search(
        self,
        query_vector: List[float],
        top_k: int = 4,
        filters: Optional[Dict[str, Any]] = None
    ) -> List[Dict[str, Any]]:
        """
        Searches for the top_k most similar chunks to the query_vector,
        optionally applying metadata filters.
        """
        pass

    @abc.abstractmethod
    def delete_document(self, document_id: str) -> None:
        """Deletes all chunks associated with a document_id."""
        pass


class InMemoryVectorStore(VectorStore):
    """
    Highly performant, thread-safe In-Memory Vector Store implementation.
    Includes robust metadata exact-match filtering.
    """
    def __init__(self):
        # Stores Chunk objects
        self._store: Dict[str, Chunk] = {}

    def add_chunks(self, chunks: List[Chunk]) -> None:
        for chunk in chunks:
            if not chunk.embedding:
                logger.warning(f"Chunk {chunk.id} is missing an embedding. Embedding was not indexed.")
            self._store[chunk.id] = chunk
        logger.info(f"Indexed {len(chunks)} chunks in the vector store. Total database size: {len(self._store)}")

    def similarity_search(
        self,
        query_vector: List[float],
        top_k: int = 4,
        filters: Optional[Dict[str, Any]] = None
    ) -> List[Dict[str, Any]]:
        results = []
        embedding_service = get_embedding_service()

        for chunk_id, chunk in self._store.items():
            if not chunk.embedding:
                continue

            # Apply Metadata Filters
            if filters:
                match = True
                for k, v in filters.items():
                    if v is not None:
                        # Exact match check
                        chunk_val = chunk.metadata.get(k)
                        if isinstance(chunk_val, str) and isinstance(v, str):
                            if chunk_val.lower() != v.lower():
                                match = False
                                break
                        elif chunk_val != v:
                            match = False
                            break
                if not match:
                    continue

            # Compute Cosine Similarity
            score = embedding_service.cosine_similarity(query_vector, chunk.embedding)
            results.append({
                "chunk": chunk,
                "score": score
            })

        # Sort by score descending
        results.sort(key=lambda x: x["score"], reverse=True)
        return results[:top_k]

    def delete_document(self, document_id: str) -> None:
        keys_to_delete = [k for k, v in self._store.items() if v.document_id == document_id]
        for k in keys_to_delete:
            del self._store[k]
        logger.info(f"Deleted {len(keys_to_delete)} chunks for document {document_id}")


# Factory/Registry to support Chroma, Pinecone, FAISS, Qdrant, Milvus
class VectorStoreFactory:
    _instance: Optional[VectorStore] = None
    _provider: str = "in_memory"

    @classmethod
    def get_vector_store(cls) -> VectorStore:
        if cls._instance is None:
            # We default to in_memory in this workspace, but the abstraction supports switching providers.
            if cls._provider == "in_memory":
                cls._instance = InMemoryVectorStore()
            elif cls._provider == "chroma":
                logger.info("Initializing ChromaDB connection...")
                # Placeholder for Chroma implementation
                cls._instance = InMemoryVectorStore() 
            elif cls._provider == "pinecone":
                logger.info("Initializing Pinecone client...")
                # Placeholder for Pinecone implementation
                cls._instance = InMemoryVectorStore()
            elif cls._provider == "qdrant":
                logger.info("Initializing Qdrant client...")
                # Placeholder for Qdrant implementation
                cls._instance = InMemoryVectorStore()
            elif cls._provider == "faiss":
                logger.info("Initializing FAISS local index...")
                cls._instance = InMemoryVectorStore()
            else:
                cls._instance = InMemoryVectorStore()
        return cls._instance

    @classmethod
    def set_provider(cls, provider: str) -> None:
        cls._provider = provider.lower()
        cls._instance = None # Reset instance to re-initialize

def get_vector_store() -> VectorStore:
    return VectorStoreFactory.get_vector_store()

import re
import logging
from typing import Dict, Any

logger = logging.getLogger("app.services.query_classifier")

class QueryClassifier:
    """
    Classifies queries locally using pattern matching and regular expressions.
    Extracts key product entities, categories, and ticket IDs to optimize routing.
    """
    @staticmethod
    def classify_query(query: str) -> Dict[str, Any]:
        q = query.lower()

        # Default classification
        category = "general"
        urgency = "medium"
        entities = {}

        # Regex Entity Extraction
        # Ticket ID pattern (e.g., TCK-12345 or TCK-999)
        ticket_match = re.search(r"tck-\d{3,6}", q)
        if ticket_match:
            entities["ticket_id"] = ticket_match.group(0).upper()
            category = "ticket_inquiry"
            urgency = "high"

        # Product matching
        products = ["cloud", "billing_system", "database", "portal", "agent_app"]
        for p in products:
            if p in q or p.replace("_", " ") in q:
                entities["product"] = p

        # Intent categorization
        if any(w in q for w in ["refund", "billing", "pricing", "cost", "invoice", "payment", "subscription"]):
            category = "billing"
            if any(w in q for w in ["charge twice", "wrong charge", "fraud"]):
                urgency = "high"
        elif any(w in q for w in ["password", "reset", "login", "account", "mfa", "sign in", "signup"]):
            category = "account"
        elif any(w in q for w in ["bug", "error", "crash", "broken", "fail", "slow", "down", "not working"]):
            category = "troubleshooting"
            urgency = "high"
        elif any(w in q for w in ["how to", "guide", "documentation", "manual", "setup", "install"]):
            category = "documentation"
            urgency = "low"

        return {
            "category": category,
            "urgency": urgency,
            "entities": entities
        }

def get_query_classifier() -> QueryClassifier:
    return QueryClassifier()

import logging
from typing import Dict, Any, Optional
from app.schemas.retrieval import RetrievalFilter

logger = logging.getLogger("app.services.metadata_filter")

class MetadataFilterBuilder:
    """
    Builds clean metadata filter dictionaries for vector store queries.
    Enforces category or product restrictions automatically if matched in the query.
    """
    @staticmethod
    def build_filters(
        request_filter: Optional[RetrievalFilter] = None,
        extracted_metadata: Optional[Dict[str, Any]] = None
    ) -> Dict[str, Any]:
        filters = {}

        # 1. Apply explicit request filters
        if request_filter:
            if request_filter.category:
                filters["category"] = request_filter.category
            if request_filter.product:
                filters["product"] = request_filter.product
            if request_filter.custom_filters:
                filters.update(request_filter.custom_filters)

        # 2. Enrich with extracted query entities if not explicitly overridden
        if extracted_metadata:
            if "product" in extracted_metadata.get("entities", {}) and "product" not in filters:
                filters["product"] = extracted_metadata["entities"]["product"]
            if extracted_metadata.get("category") and extracted_metadata["category"] != "general" and "category" not in filters:
                # We can choose to filter by category or keep it broad. Let's keep it broad unless it's a critical category.
                if extracted_metadata["category"] in ["billing", "account"]:
                    filters["category"] = extracted_metadata["category"]

        return filters

def get_metadata_filter_builder() -> MetadataFilterBuilder:
    return MetadataFilterBuilder()
